package com.example.app.network.interceptor

import com.example.app.network.TokenProvider
import okhttp3.Interceptor
import okhttp3.Response

class TokenRefreshInterceptor(private val tokenProvider: TokenProvider) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val response = chain.proceed(chain.request())

        if (response.code == 401) {
            // Token expired - clear tokens and signal re-authentication needed
            // In production, you'd implement token refresh logic here
            tokenProvider.clearTokens()
        }

        return response
    }
}

