package com.example.app.network

import com.example.app.network.api.AuthApiService
import com.example.app.network.api.UserApiService
import com.example.app.network.interceptor.AuthInterceptor
import com.example.app.network.interceptor.TokenRefreshInterceptor
import com.google.gson.GsonBuilder
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private var retrofit: Retrofit? = null
    private var tokenProvider: TokenProvider? = null

    private const val CONNECT_TIMEOUT = 30L
    private const val READ_TIMEOUT = 30L
    private const val WRITE_TIMEOUT = 30L

    fun init(tokenProvider: TokenProvider, environment: Environment = Environment.DEV) {
        this.tokenProvider = tokenProvider
        Environment.current = environment
        retrofit = null // Reset to rebuild with new environment
    }

    fun switchEnvironment(environment: Environment) {
        Environment.current = environment
        retrofit = null // Force rebuild
    }

    private fun provideLoggingInterceptor(): HttpLoggingInterceptor {
        val level = when (Environment.current) {
            Environment.DEV -> HttpLoggingInterceptor.Level.BODY
            Environment.STAGING -> HttpLoggingInterceptor.Level.HEADERS
            Environment.PRODUCTION -> HttpLoggingInterceptor.Level.NONE
        }
        return HttpLoggingInterceptor().apply { this.level = level }
    }

    private fun provideOkHttpClient(): OkHttpClient {
        val provider = tokenProvider
            ?: throw IllegalStateException("NetworkModule not initialized. Call init() first.")

        return OkHttpClient.Builder()
            .connectTimeout(CONNECT_TIMEOUT, TimeUnit.SECONDS)
            .readTimeout(READ_TIMEOUT, TimeUnit.SECONDS)
            .writeTimeout(WRITE_TIMEOUT, TimeUnit.SECONDS)
            .addInterceptor(AuthInterceptor(provider))
            .addInterceptor(provideLoggingInterceptor())
            .addInterceptor(TokenRefreshInterceptor(provider))
            .build()
    }

    private fun provideRetrofit(): Retrofit {
        return retrofit ?: synchronized(this) {
            retrofit ?: Retrofit.Builder()
                .baseUrl(Environment.current.baseUrl)
                .client(provideOkHttpClient())
                .addConverterFactory(
                    GsonConverterFactory.create(
                        GsonBuilder()
                            .setLenient()
                            .create()
                    )
                )
                .build()
                .also { retrofit = it }
        }
    }

    val userApiService: UserApiService
        get() = provideRetrofit().create(UserApiService::class.java)

    val authApiService: AuthApiService
        get() = provideRetrofit().create(AuthApiService::class.java)
}

