package com.example.app.network.repository

import com.example.app.network.NetworkModule
import com.example.app.network.NetworkResult
import com.example.app.network.TokenProvider
import com.example.app.network.api.AuthTokenResponse
import com.example.app.network.api.LoginRequest
import com.example.app.network.model.ApiResponse
import com.example.app.network.safeApiCall

class AuthRepository(private val tokenProvider: TokenProvider) {

    private val authApi = NetworkModule.authApiService

    suspend fun login(email: String, password: String): NetworkResult<ApiResponse<AuthTokenResponse>> {
        val result = safeApiCall { authApi.login(LoginRequest(email, password)) }
        if (result is NetworkResult.Success) {
            result.data.data?.let { tokenResponse ->
                tokenProvider.saveAccessToken(tokenResponse.accessToken)
                tokenProvider.saveRefreshToken(tokenResponse.refreshToken)
            }
        }
        return result
    }

    suspend fun refreshToken(): NetworkResult<ApiResponse<AuthTokenResponse>> {
        val refreshToken = tokenProvider.getRefreshToken() ?: return NetworkResult.Error(401, "No refresh token")
        val result = safeApiCall {
            authApi.refreshToken(mapOf("refresh_token" to refreshToken))
        }
        if (result is NetworkResult.Success) {
            result.data.data?.let { tokenResponse ->
                tokenProvider.saveAccessToken(tokenResponse.accessToken)
                tokenProvider.saveRefreshToken(tokenResponse.refreshToken)
            }
        }
        return result
    }

    suspend fun logout(): NetworkResult<ApiResponse<Unit>> {
        val result = safeApiCall { authApi.logout() }
        tokenProvider.clearTokens()
        return result
    }
}

