package com.example.app.ui

import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.app.network.NetworkResult
import com.example.app.network.model.UserProfile
import com.example.app.network.repository.UserRepository
import kotlinx.coroutines.launch

class UserViewModel : ViewModel() {

    private val userRepository = UserRepository()

    private val _users = MutableLiveData<List<UserProfile>>()
    val users: LiveData<List<UserProfile>> = _users

    private val _currentUser = MutableLiveData<UserProfile?>()
    val currentUser: LiveData<UserProfile?> = _currentUser

    private val _loading = MutableLiveData<Boolean>()
    val loading: LiveData<Boolean> = _loading

    private val _error = MutableLiveData<String?>()
    val error: LiveData<String?> = _error

    fun fetchUsers(page: Int = 1) {
        viewModelScope.launch {
            _loading.value = true
            _error.value = null

            when (val result = userRepository.getUsers(page)) {
                is NetworkResult.Success -> {
                    _users.value = result.data.data
                }
                is NetworkResult.Error -> {
                    _error.value = "Error ${result.code}: ${result.message}"
                }
                is NetworkResult.Exception -> {
                    _error.value = result.throwable.localizedMessage ?: "Unknown error"
                }
            }

            _loading.value = false
        }
    }

    fun fetchCurrentUser() {
        viewModelScope.launch {
            _loading.value = true
            _error.value = null

            when (val result = userRepository.getCurrentUser()) {
                is NetworkResult.Success -> {
                    _currentUser.value = result.data.data
                }
                is NetworkResult.Error -> {
                    _error.value = "Error ${result.code}: ${result.message}"
                }
                is NetworkResult.Exception -> {
                    _error.value = result.throwable.localizedMessage ?: "Unknown error"
                }
            }

            _loading.value = false
        }
    }

    fun fetchUserById(userId: Long) {
        viewModelScope.launch {
            _loading.value = true
            _error.value = null

            when (val result = userRepository.getUserById(userId)) {
                is NetworkResult.Success -> {
                    _currentUser.value = result.data.data
                }
                is NetworkResult.Error -> {
                    _error.value = "Error ${result.code}: ${result.message}"
                }
                is NetworkResult.Exception -> {
                    _error.value = result.throwable.localizedMessage ?: "Unknown error"
                }
            }

            _loading.value = false
        }
    }

    fun searchUsers(query: String) {
        viewModelScope.launch {
            _loading.value = true
